from java.io import File
def get_directory_tree(starting_dir):
	def build_tree(directory):
		if not directory.exists() or not directory.isDirectory():
		    return []

		items = []
		for file in directory.listFiles():
		    item = {
		        "label": file.getName(),
		        "expanded": False,
		        "data": file.getAbsolutePath(),
		        "items": build_tree(file) if file.isDirectory() else []
		    }
		    items.append(item)
		items.sort(key=lambda x: x["label"])
		return items

	directory = File(starting_dir)
	return build_tree(directory)

directory = get_directory_tree('/usr/local/bin/ignition/')

self.props.items = directory

from java.io import File

def get_currently_expanded_paths(tree_items_list):
    expanded_paths = set()

    def find_expanded(current_items):
        if current_items is None:
            return
        for item in current_items:
            if item.get("expanded", False) and item.get("data"):
                expanded_paths.add(item.get("data"))

            if item.get("items"):
                find_expanded(item.get("items"))

    find_expanded(tree_items_list)
    return expanded_paths

def get_directory_tree_with_state(starting_dir, previously_expanded_paths):
    def build_tree(directory, expanded_paths_set):
        if not directory.exists() or not directory.isDirectory():
            return []

        items = []
        files_in_directory = directory.listFiles()

        if files_in_directory is None:
            return []

        for file_obj in files_in_directory:
            absolute_path = file_obj.getAbsolutePath()
            is_expanded = absolute_path in expanded_paths_set

            item = {
                "label": file_obj.getName(),
                "expanded": is_expanded,
                "data": absolute_path,
                "items": build_tree(file_obj, expanded_paths_set) if file_obj.isDirectory() else []
            }
            items.append(item)

        items.sort(key=lambda x: x["label"])

        return items

    root_directory_obj = File(starting_dir)
    return build_tree(root_directory_obj, previously_expanded_paths)

try:
    current_tree_props_items = self.getSibling("Tree").props.items
except AttributeError:
    current_tree_props_items = []

expanded_paths_before_refresh = get_currently_expanded_paths(current_tree_props_items)

starting_directory_path = '/usr/local/bin/ignition/' 

new_directory_tree_data = get_directory_tree_with_state(starting_directory_path, expanded_paths_before_refresh)

self.getSibling("Tree").props.items = new_directory_tree_data
